INSERT INTO security_risks (id, risk_no, title, description, source, category, level, affected_assets, cvss_score, cve_id, impact_score, likelihood_score, total_score, status, workflow_status, risk_owner_id, handler_id, discovery_date, plan_end_date, actual_end_date, attachments, created_at, updated_at) VALUES
(1, 'SEC-2026-001', 'Apache Log4j2 远程代码执行漏洞（CVE-2021-44228）', 'Apache Log4j2 存在 JNDI 注入漏洞，攻击者可通过构造恶意日志消息实现远程代码执行，影响所有使用 Log4j2 2.0-beta9 至 2.14.1 版本的应用系统。', '外部来源', '漏洞利用', '严重', '["核心业务系统","用户管理平台","数据分析平台"]', 10.0, 'CVE-2021-44228', 10, 5, 25, '已修复', 'closed', 3, 4, '2026-01-15T08:00:00Z', '2026-02-15T00:00:00Z', '2026-02-10T14:30:00Z', '[]', '2026-01-15T08:00:00Z', '2026-02-10T14:30:00Z'),
(2, 'SEC-2026-002', '客户管理系统 SQL 注入漏洞', '客户管理系统的查询接口存在 SQL 注入漏洞，攻击者可通过构造特殊请求获取数据库敏感信息，包括客户个人数据和交易记录。', '内部来源', '漏洞利用', '高危', '["客户管理系统","数据库服务器"]', 8.5, NULL, 5, 4, 20, '处置中', 'in_progress', 3, 4, '2026-03-10T10:00:00Z', '2026-06-30T00:00:00Z', NULL, '[]', '2026-03-10T10:00:00Z', '2026-03-15T10:00:00Z'),
(3, 'SEC-2026-003', 'OpenSSL 缓冲区溢出漏洞（CVE-2024-5535）', 'OpenSSL 存在缓冲区溢出漏洞，可能导致拒绝服务或远程代码执行，影响所有使用该版本 OpenSSL 的服务。', '外部来源', '漏洞利用', '高危', '["Web 服务器集群","API 网关","邮件服务器"]', 7.8, NULL, 4, 4, 16, '处置中', 'in_progress', 3, 5, '2026-04-05T08:00:00Z', '2026-07-15T00:00:00Z', NULL, '[]', '2026-04-05T08:00:00Z', '2026-04-10T09:00:00Z'),
(4, 'SEC-2026-004', 'Spring Framework 路径遍历漏洞（CVE-2024-22263）', 'Spring Framework 的静态资源处理存在路径遍历漏洞，攻击者可读取服务器上的敏感文件。', '外部来源', '漏洞利用', '中危', '["内部办公系统","HR 管理平台"]', 6.5, NULL, 4, 3, 12, '待处置', 'assigned', 3, NULL, '2026-05-01T08:00:00Z', '2026-07-20T00:00:00Z', NULL, '[]', '2026-05-01T08:00:00Z', '2026-05-05T10:00:00Z'),
(5, 'SEC-2026-005', '管理员账户弱密码及未启用 MFA', '安全审计发现多个管理员账户使用弱密码，且未启用多因素认证，存在被暴力破解的风险。', '内部来源', '身份与访问', '高危', '["AD 域控制器","VPN 网关","堡垒机"]', NULL, NULL, 5, 4, 20, '已修复', 'closed', 2, 4, '2026-03-20T08:00:00Z', '2026-04-10T00:00:00Z', '2026-04-08T15:00:00Z', '[]', '2026-03-20T08:00:00Z', '2026-04-08T15:00:00Z'),
(6, 'SEC-2026-006', 'Jenkins CI/CD 服务器多个安全漏洞', 'Jenkins 服务器存在多个已知安全漏洞，包括未授权访问、CSRF 和 XSS 漏洞，可能被攻击者利用获取代码仓库访问权限。', '内部来源', '配置缺陷', '高危', '["CI/CD 平台","代码仓库"]', 8.2, NULL, 4, 4, 16, '处置中', 'in_progress', 2, 5, '2026-05-15T08:00:00Z', '2026-07-01T00:00:00Z', NULL, '[]', '2026-05-15T08:00:00Z', '2026-05-20T10:00:00Z'),
(7, 'SEC-2026-007', '第三方依赖库 License 合规风险', '代码扫描发现项目中使用了多个 GPL 协议的开源组件，存在 License 合规风险，可能影响产品商业化发布。', '内部来源', '合规与法规', '低危', '["产品代码库"]', NULL, NULL, 3, 2, 6, '已接受', 'closed', 3, NULL, '2026-05-05T08:00:00Z', '2026-05-30T00:00:00Z', '2026-05-25T10:00:00Z', '[]', '2026-05-05T08:00:00Z', '2026-05-25T10:00:00Z'),
(8, 'SEC-2026-008', '内部网络横向移动风险', '安全评估发现内部网络缺乏有效的分段隔离，攻击者一旦突破边界防护可在内网自由横向移动，威胁核心数据安全。', '内部来源', '配置缺陷', '高危', '["内部网络","数据库集群","文件服务器"]', NULL, NULL, 5, 3, 15, '处置中', 'in_progress', 2, 5, '2026-05-22T08:00:00Z', '2026-07-10T00:00:00Z', NULL, '[]', '2026-05-22T08:00:00Z', '2026-05-28T10:00:00Z'),
(9, 'SEC-2026-009', '日志系统存储空间不足风险', '安全日志系统存储空间即将耗尽，可能导致安全事件无法被完整记录和追溯，影响安全审计和事件响应能力。', '内部来源', '配置缺陷', '中危', '["SIEM 平台","日志存储服务器"]', NULL, NULL, 3, 4, 12, '待处置', 'assigned', 2, NULL, '2026-05-28T08:00:00Z', '2026-08-01T00:00:00Z', NULL, '[]', '2026-05-28T08:00:00Z', '2026-06-01T10:00:00Z'),
(10, 'SEC-2026-010', 'Redis 未授权访问漏洞', '内网 Redis 实例未启用密码认证，且绑定地址为 0.0.0.0，存在被未授权访问和恶意写入的风险。', '内部来源', '配置缺陷', '高危', '["缓存服务器","会话存储"]', 7.5, NULL, 4, 4, 16, '已修复', 'closed', 2, 5, '2026-02-20T08:00:00Z', '2026-03-10T00:00:00Z', '2026-03-05T17:00:00Z', '[]', '2026-02-20T08:00:00Z', '2026-03-05T17:00:00Z'),
(11, 'SEC-2026-011', 'Nginx HTTP/2 快速重置漏洞（CVE-2024-28118）', 'Nginx HTTP/2 实现存在快速重置攻击漏洞，攻击者可利用该漏洞发起拒绝服务攻击，导致 Web 服务不可用。', '外部来源', '漏洞利用', '中危', '["Web 服务器集群","CDN 节点"]', 6.2, NULL, 4, 3, 12, '处置中', 'in_progress', 3, 5, '2026-06-01T08:00:00Z', '2026-07-25T00:00:00Z', NULL, '[]', '2026-06-01T08:00:00Z', '2026-06-05T10:00:00Z'),
(12, 'SEC-2026-012', 'Web 应用跨站脚本攻击（XSS）风险', '多个 Web 应用未对用户输入进行充分转义，存在存储型 XSS 漏洞，攻击者可注入恶意脚本窃取用户会话信息。', '内部来源', '漏洞利用', '中危', '["客户门户","员工自助平台"]', 6.1, NULL, 4, 3, 12, '处置中', 'in_progress', 3, 4, '2026-06-03T08:00:00Z', '2026-07-30T00:00:00Z', NULL, '[]', '2026-06-03T08:00:00Z', '2026-06-08T10:00:00Z'),
(13, 'SEC-2026-013', 'Kubernetes 容器逃逸漏洞（CVE-2024-31317）', 'Kubernetes 集群使用的 containerd 版本存在容器逃逸漏洞，攻击者可从容器内逃逸到宿主机，获取主机控制权。', '外部来源', '漏洞利用', '严重', '["Kubernetes 集群","生产环境容器"]', 9.8, NULL, 5, 4, 20, '待处置', 'assigned', 2, NULL, '2026-06-08T08:00:00Z', '2026-08-15T00:00:00Z', NULL, '[]', '2026-06-08T08:00:00Z', '2026-06-10T10:00:00Z'),
(14, 'SEC-2026-014', 'TLS 协议版本过低风险', '部分对外服务仍支持 TLS 1.0 和 TLS 1.1 协议，这些协议版本已被证实存在安全弱点，不满足 PCI-DSS 合规要求。', '内部来源', '合规与法规', '中危', '["支付网关","客户门户","API 服务"]', NULL, NULL, 3, 3, 9, '已修复', 'closed', 3, 5, '2026-03-28T08:00:00Z', '2026-04-15T00:00:00Z', '2026-04-12T14:00:00Z', '[]', '2026-03-28T08:00:00Z', '2026-04-12T14:00:00Z'),
(15, 'SEC-2026-015', '微服务 API 接口缺乏认证和限流', '内部微服务 API 接口未实施统一的认证机制和请求限流策略，存在被滥用和拒绝服务攻击的风险。', '内部来源', '配置缺陷', '中危', '["微服务平台","API 网关"]', NULL, NULL, 4, 3, 12, '处置中', 'in_progress', 2, 4, '2026-06-10T08:00:00Z', '2026-08-20T00:00:00Z', NULL, '[]', '2026-06-10T08:00:00Z', '2026-06-15T10:00:00Z');
