INSERT INTO knowledge_base (id, title, content, category, tags, source_type, source_ref, related_risk_ids, view_count, reference_count, is_published, created_by, updated_by, published_at, created_at, updated_at) VALUES
(1, 'Log4j2 漏洞修复指南', '详细介绍了 Log4j2 远程代码执行漏洞的修复步骤，包括版本升级、JNDI 配置禁用、WAF 规则部署等临时和永久修复方案。适用于所有使用 Java 日志框架的应用系统。', '漏洞修复', '["Log4j2","JNDI","远程代码执行","Java"]', 'external_cve', 'CVE-2021-44228', '[1]', 156, 12, 1, 2, 2, '2026-01-20T10:00:00Z', '2026-01-18T10:00:00Z', '2026-02-15T10:00:00Z'),
(2, 'SQL 注入防护最佳实践', '总结了 SQL 注入漏洞的常见类型、检测方法和防护措施。包括参数化查询、输入校验、ORM 安全使用、WAF 规则配置等内容。', '最佳实践', '["SQL注入","OWASP","输入校验","参数化查询"]', 'manual', NULL, '[2]', 98, 8, 1, 2, 2, '2026-03-12T10:00:00Z', '2026-03-10T10:00:00Z', '2026-03-12T10:00:00Z'),
(3, '《网络安全等级保护基本要求》合规要点', '梳理了等保 2.0 标准中与网络安全风险管理相关的合规要求，包括安全通信网络、安全区域边界、安全计算环境等方面的具体要求。', '合规要求', '["等保2.0","合规","等级保护","安全标准"]', 'manual', NULL, '[7,14]', 234, 25, 1, 1, 1, '2026-02-01T10:00:00Z', '2026-01-28T10:00:00Z', '2026-04-01T10:00:00Z'),
(4, '应急响应流程与模板', '提供了安全事件应急响应的标准流程，包括事件发现、初步评估、遏制措施、根因分析、修复验证和事后总结等阶段。附带各阶段的操作模板和检查清单。', '应急响应', '["应急响应","事件处理","安全事件","流程模板"]', 'manual', NULL, '[1,5,13]', 187, 20, 1, 2, 2, '2026-02-10T10:00:00Z', '2026-02-05T10:00:00Z', '2026-05-20T10:00:00Z'),
(5, 'Kubernetes 安全加固配置指南', '介绍了 Kubernetes 集群的安全加固配置，包括 RBAC 配置、网络策略、Pod 安全标准、镜像扫描、Secret 管理等安全最佳实践。', '配置加固', '["Kubernetes","容器安全","K8s","安全加固"]', 'manual', NULL, '[13]', 112, 15, 1, 2, 2, '2026-04-15T10:00:00Z', '2026-04-10T10:00:00Z', '2026-06-05T10:00:00Z');
INSERT INTO ai_analysis_records (id, risk_id, input_text, analysis_result, suggested_level, suggested_measures, suggested_category, suggested_source, suggested_impact_score, suggested_likelihood_score, confidence_score, model_provider, model_name, is_applied, created_by, created_at) VALUES
(1, 2, '客户管理系统的查询接口存在 SQL 注入漏洞，攻击者可通过构造特殊请求获取数据库敏感信息。', '{"severity":"high","attack_vector":"network","complexity":"low"}', '高危', '[{"type":"修复","description":"对所有数据库查询实施参数化处理","priority":"P0"},{"type":"缓解","description":"部署 WAF SQL 注入检测规则","priority":"P1"}]', '漏洞利用', '内部来源', 5, 4, 0.92, 'openai', 'gpt-4o', 1, 2, '2026-03-10T10:30:00Z'),
(2, 13, 'Kubernetes 集群使用的 containerd 版本存在容器逃逸漏洞，攻击者可从容器内逃逸到宿主机。', '{"severity":"critical","attack_vector":"adjacent","complexity":"low"}', '严重', '[{"type":"修复","description":"升级 containerd 至安全版本","priority":"P0"},{"type":"缓解","description":"启用 Pod 安全标准（restricted）","priority":"P1"},{"type":"缓解","description":"限制容器以非 root 用户运行","priority":"P1"}]', '漏洞利用', '外部来源', 5, 4, 0.88, 'openai', 'gpt-4o', 1, 2, '2026-06-08T08:30:00Z'),
(3, NULL, '收到外部安全厂商通报，某开源组件存在 0day 漏洞，影响范围广泛，建议尽快排查。', '{"severity":"medium","potential_impact":"需要进一步评估"}', '中危', '[{"type":"缓解","description":"排查内部系统是否使用该组件","priority":"P0"},{"type":"缓解","description":"临时禁用相关功能模块","priority":"P1"}]', '供应链风险', '外部来源', 3, 3, 0.65, 'openai', 'gpt-4o', 0, 2, '2026-06-15T14:00:00Z');
